from typing_extensions import TypedDict


# No totality because all these private fields can be NOT present in an initial cloud.
class PrivateNamespace(TypedDict, total=False):
    """
    This stores possible private metadata that we know how to convert from and to VLR
    format.

    - inners: the number of first points that are within the inner portion of a tile
        of a cloud which was tiled with padding.
    """

    inners: int
